/**
 * Walking Skeleton Acceptance Tests - Grocery List UI
 *
 * These tests form the outer loop of Outside-In TDD for the UI layer.
 * They render components via ServiceProvider with null adapters and
 * verify observable user outcomes through screen queries.
 *
 * Strategy: ONE test enabled at a time. Implement until it passes,
 * then enable the next. All tests after the first use it.skip().
 *
 * Driving Ports:
 * - UI: React components rendered with ServiceProvider
 * - User actions: fireEvent (tap, changeText)
 * - Assertions: screen queries (getByText, queryByText, getByTestId)
 *
 * Story Trace:
 * - UI-WS-1: Home view renders staples grouped by house area
 * - UI-WS-2: Quick-add places a new item on the trip
 * - UI-WS-3: Toggle from home view to store view
 * - UI-WS-4: Store view renders items grouped by aisle
 * - UI-WS-5: Check off an item in store view
 * - UI-WS-6: Trip completion shows summary with carryover
 */

// --- Driving port imports ---
// Domain ports (already implemented):
import { createStapleLibrary } from '../../../src/domain/staple-library';
import { createTrip, completeTrip } from '../../../src/domain/trip';
import { createNullStapleStorage } from '../../../src/adapters/null/null-staple-storage';
import { createNullTripStorage } from '../../../src/adapters/null/null-trip-storage';

// UI ports (to be created during DELIVER wave):
import { render, fireEvent, screen, waitFor } from '@testing-library/react-native';
import { ServiceProvider } from '../../../src/ui/ServiceProvider';
import { AppShell } from '../../../src/ui/AppShell';

// =============================================================================
// Shared test setup
// =============================================================================

function createTestServices() {
  const stapleStorage = createNullStapleStorage([
    { name: 'Whole milk', houseArea: 'Fridge', storeLocation: { section: 'Dairy', aisleNumber: 3 } },
    { name: 'Butter', houseArea: 'Fridge', storeLocation: { section: 'Dairy', aisleNumber: 3 } },
    { name: 'Toilet paper', houseArea: 'Bathroom', storeLocation: { section: 'Paper Goods', aisleNumber: 8 } },
    { name: 'Shampoo', houseArea: 'Bathroom', storeLocation: { section: 'Personal Care', aisleNumber: 7 } },
    { name: 'Canned beans', houseArea: 'Garage Pantry', storeLocation: { section: 'Canned Goods', aisleNumber: 5 } },
  ]);
  const library = createStapleLibrary(stapleStorage);
  const tripStorage = createNullTripStorage();
  const tripService = createTrip(tripStorage);
  tripService.start(library.listAll());
  return { library, tripService, stapleStorage, tripStorage };
}

// =============================================================================
// UI-WS-1: Home view renders staples grouped by house area
// =============================================================================

describe('UI-WS-1: Home view shows staples organized by house area', () => {
  // AC: Home screen displays trip items grouped by their house area
  // AC: Each area section shows item names within it
  // Trace: US-02 (UI rendering)

  it('displays staples under their house area headings', () => {
    // Given Carlos has staples across Fridge, Bathroom, and Garage Pantry
    const { library, tripService } = createTestServices();

    // When Carlos opens the home screen
    render(
      <ServiceProvider stapleLibrary={library} tripService={tripService}>
        <AppShell />
      </ServiceProvider>
    );

    // Then Carlos sees "Fridge" area with "Whole milk" and "Butter"
    expect(screen.getByText('Fridge (2)')).toBeTruthy();
    expect(screen.getByText('Whole milk')).toBeTruthy();
    expect(screen.getByText('Butter')).toBeTruthy();

    // And Carlos sees "Bathroom" area with "Toilet paper" and "Shampoo"
    expect(screen.getByText('Bathroom (2)')).toBeTruthy();
    expect(screen.getByText('Toilet paper')).toBeTruthy();
    expect(screen.getByText('Shampoo')).toBeTruthy();

    // And Carlos sees "Garage Pantry" area with "Canned beans"
    expect(screen.getByText('Garage Pantry (1)')).toBeTruthy();
    expect(screen.getByText('Canned beans')).toBeTruthy();
  });
});

// =============================================================================
// UI-WS-2: Quick-add places a new item on the trip
// =============================================================================

describe('UI-WS-2: Quick-add places a new item on the trip', () => {
  // AC: Typing a name and submitting adds the item to the visible trip
  // Trace: US-03 (UI rendering)

  it('adds a quick-add item that appears on the home screen', () => {
    // Given Carlos has an active trip displayed on the home screen
    const { library, tripService } = createTestServices();
    render(
      <ServiceProvider stapleLibrary={library} tripService={tripService}>
        <AppShell />
      </ServiceProvider>
    );

    // When Carlos types "Greek yogurt" in the quick-add field and taps Add
    const quickAddInput = screen.getByPlaceholderText('Add an item...');
    fireEvent.changeText(quickAddInput, 'Greek yogurt');
    fireEvent.press(screen.getByText('Add'));

    // Then the metadata sheet opens; Carlos skips metadata and adds with defaults
    fireEvent.press(screen.getByText('Skip, add with defaults'));

    // Then "Greek yogurt" appears on the home screen
    expect(screen.getByText('Greek yogurt')).toBeTruthy();
  });
});

// =============================================================================
// UI-WS-3: Toggle from home view to store view
// =============================================================================

describe('UI-WS-3: Toggle switches from home view to store view', () => {
  // AC: Tapping the view toggle switches visible content
  // AC: Home view content disappears when store view is active
  // Trace: US-04 (UI rendering)

  it('hides home view and shows store view on toggle tap', () => {
    // Given Carlos is viewing the home screen
    const { library, tripService } = createTestServices();
    render(
      <ServiceProvider stapleLibrary={library} tripService={tripService}>
        <AppShell />
      </ServiceProvider>
    );
    expect(screen.getByText('Fridge (2)')).toBeTruthy();

    // When Carlos taps the store view toggle
    fireEvent.press(screen.getByText('Store'));

    // Then the store view is displayed
    expect(screen.getByText('Dairy')).toBeTruthy();

    // And the home view area headings are no longer visible
    expect(screen.queryByText('Fridge (2)')).toBeNull();
  });
});

// =============================================================================
// UI-WS-4: Store view renders items grouped by aisle
// =============================================================================

describe('UI-WS-4: Store view shows items organized by aisle and section', () => {
  // AC: Store view groups items by aisle number ascending, then named sections
  // Trace: US-04 (UI rendering)

  it('displays items under aisle and section headings', () => {
    // Given Carlos has an active trip and switches to store view
    const { library, tripService } = createTestServices();
    render(
      <ServiceProvider stapleLibrary={library} tripService={tripService}>
        <AppShell />
      </ServiceProvider>
    );
    fireEvent.press(screen.getByText('Store'));

    // When the store view renders
    // (already rendered after toggle)

    // Then Carlos sees the "Dairy" section with "Whole milk" and "Butter"
    expect(screen.getByText('Dairy')).toBeTruthy();
    expect(screen.getByText('Whole milk')).toBeTruthy();
    expect(screen.getByText('Butter')).toBeTruthy();

    // And Carlos sees the "Canned Goods" section with "Canned beans"
    expect(screen.getByText('Canned Goods')).toBeTruthy();
    expect(screen.getByText('Canned beans')).toBeTruthy();

    // Section ordering follows groupBySection (alphabetical by default).
  });
});

// =============================================================================
// UI-WS-5: Check off an item in store view
// =============================================================================

describe('UI-WS-5: Tapping an item in store view marks it as in the cart', () => {
  // AC: Tapping an item toggles its checked state visually
  // Trace: US-05 (UI rendering)

  it('shows item as checked after tap', () => {
    // Given Carlos is viewing the store view
    const { library, tripService } = createTestServices();
    render(
      <ServiceProvider stapleLibrary={library} tripService={tripService}>
        <AppShell />
      </ServiceProvider>
    );
    fireEvent.press(screen.getByText('Store'));

    // When Carlos taps "Whole milk" to check it off
    fireEvent.press(screen.getByText('Whole milk'));

    // Then "Whole milk" appears as checked off (strikethrough or checkmark visible)
    expect(screen.getByTestId('checked-Whole milk')).toBeTruthy();
  });
});

// =============================================================================
// UI-WS-6: Trip completion shows summary with carryover
// =============================================================================

describe('UI-WS-6: Completing the trip shows a summary with carryover', () => {
  // AC: After finishing the trip, a summary screen appears
  // AC: Summary shows purchased count and carryover items
  // Trace: US-06 (UI rendering)

  it('displays trip summary with purchased and carryover counts', () => {
    // Given Carlos has checked off "Whole milk" and "Butter" but not "Canned beans"
    const { library, tripService } = createTestServices();
    render(
      <ServiceProvider stapleLibrary={library} tripService={tripService}>
        <AppShell />
      </ServiceProvider>
    );
    fireEvent.press(screen.getByText('Store'));
    fireEvent.press(screen.getByText('Whole milk'));
    fireEvent.press(screen.getByText('Butter'));

    // When Carlos finishes the trip
    fireEvent.press(screen.getByText('Finish Trip'));

    // Then Carlos sees a trip summary showing 2 items purchased
    expect(screen.getByText('2 items purchased')).toBeTruthy();

    // And the summary indicates "Canned beans" will carry over
    expect(screen.getByText('Canned beans')).toBeTruthy();
    expect(screen.getByText(/carry over/i)).toBeTruthy();
  });
});

tests/regression/sweep-ux-refresh.test.t.source:
/**
 * Sweep UX Refresh - Steps 01-01 and 01-02
 *
 * 01-01: Home mode tap toggles needed state with green/grey styling.
 * 01-02: Home mode long-press opens edit sheet; no skip section in AreaSection.
 *
 * New behavior:
 * - Tap calls onPress (not onEditStaple)
 * - No Skip button in home mode
 * - Needed items: green text (#4CAF50)
 * - Skipped items: grey text (#999999) with strikethrough
 * - Long-press calls onLongPress in home mode (same as store mode)
 * - AreaSection renders all items inline (no separate skipped section or Re-add buttons)
 */

import React from 'react';
import { render, fireEvent, screen } from '@testing-library/react-native';
import { TripItemRow } from '../../src/ui/TripItemRow';
import { AreaSection } from '../../src/ui/AreaSection';
import { AreaGroup } from '../../src/domain/item-grouping';
import { TripItem } from '../../src/domain/types';
import { ServiceProvider } from '../../src/ui/ServiceProvider';
import { AppShell } from '../../src/ui/AppShell';
import { createStapleLibrary } from '../../src/domain/staple-library';
import { createNullStapleStorage } from '../../src/adapters/null/null-staple-storage';
import { createNullTripStorage } from '../../src/adapters/null/null-trip-storage';
import { createTrip } from '../../src/domain/trip';

const createTripItem = (overrides?: Partial<TripItem>): TripItem => ({
  id: 'item-1',
  name: 'Milk',
  houseArea: 'Fridge',
  storeLocation: { section: 'Dairy', aisleNumber: 2 },
  itemType: 'staple',
  stapleId: 'staple-1',
  source: 'preloaded',
  needed: true,
  checked: false,
  checkedAt: null,
  ...overrides,
});

describe('home mode tap toggles needed state with green/grey', () => {
  it('tap calls onPress, not onEditStaple, for staple items in home mode', () => {
    const onPress = jest.fn();
    const onEditStaple = jest.fn();
    const item = createTripItem();

    render(
      <TripItemRow
        item={item}
        mode="home"
        onPress={onPress}
        onEditStaple={onEditStaple}
      />
    );

    fireEvent.press(screen.getByText('Milk'));

    expect(onPress).toHaveBeenCalledTimes(1);
    expect(onEditStaple).not.toHaveBeenCalled();
  });

  it('does not render a Skip button in home mode', () => {
    const onSkip = jest.fn();
    const item = createTripItem();

    render(
      <TripItemRow
        item={item}
        mode="home"
        onSkip={onSkip}
      />
    );

    expect(screen.queryByText('Skip')).toBeNull();
  });

  it('renders needed item with green text color', () => {
    const item = createTripItem({ needed: true });

    render(
      <TripItemRow
        item={item}
        mode="home"
      />
    );

    const text = screen.getByText('Milk');
    const flatStyle = Array.isArray(text.props.style)
      ? Object.assign({}, ...text.props.style.filter(Boolean))
      : text.props.style;

    expect(flatStyle.color).toBe('#1A1A1A');
  });

  it('renders skipped item with grey strikethrough text', () => {
    const item = createTripItem({ needed: false });

    render(
      <TripItemRow
        item={item}
        mode="home"
      />
    );

    const text = screen.getByText('Milk');
    const flatStyle = Array.isArray(text.props.style)
      ? Object.assign({}, ...text.props.style.filter(Boolean))
      : text.props.style;

    expect(flatStyle.color).toBe('#6B6B6B');
    expect(flatStyle.textDecorationLine).toBe('line-through');
  });
});

describe('home mode long-press opens edit and no skip section', () => {
  const createAreaGroup = (items: TripItem[]): AreaGroup => ({
    area: 'Fridge',
    items,
    neededCount: items.filter((i) => i.needed).length,
    totalCount: items.length,
  });

  it('long-press calls onLongPress with name and area in home mode', () => {
    const onLongPress = jest.fn();
    const item = createTripItem();

    render(
      <TripItemRow
        item={item}
        mode="home"
        onLongPress={onLongPress}
      />
    );

    fireEvent(screen.getByText('Milk'), 'longPress');

    expect(onLongPress).toHaveBeenCalledWith('Milk', 'Fridge');
    expect(onLongPress).toHaveBeenCalledTimes(1);
  });

  it('AreaSection does not render Re-add buttons', () => {
    const skippedItem = createTripItem({ id: 'item-2', name: 'Butter', needed: false });
    const areaGroup = createAreaGroup([createTripItem(), skippedItem]);

    render(<AreaSection areaGroup={areaGroup} />);

    expect(screen.queryByText('Re-add')).toBeNull();
    expect(screen.queryByTestId('readd-Butter')).toBeNull();
  });

  it('AreaSection renders both needed and skipped items inline', () => {
    const neededItem = createTripItem({ id: 'item-1', name: 'Milk', needed: true });
    const skippedItem = createTripItem({ id: 'item-2', name: 'Butter', needed: false });
    const areaGroup = createAreaGroup([neededItem, skippedItem]);

    render(<AreaSection areaGroup={areaGroup} />);

    // Both items visible
    expect(screen.getByText('Milk')).toBeTruthy();
    expect(screen.getByText('Butter')).toBeTruthy();
  });

  it('AreaSection passes onItemLongPress to TripItemRow', () => {
    const onItemLongPress = jest.fn();
    const item = createTripItem();
    const areaGroup = createAreaGroup([item]);

    render(
      <AreaSection
        areaGroup={areaGroup}
        onItemLongPress={onItemLongPress}
      />
    );

    fireEvent(screen.getByText('Milk'), 'longPress');

    expect(onItemLongPress).toHaveBeenCalledWith('Milk', 'Fridge');
  });

  it('AreaSection passes onItemPress for toggle', () => {
    const onItemPress = jest.fn();
    const item = createTripItem();
    const areaGroup = createAreaGroup([item]);

    render(
      <AreaSection
        areaGroup={areaGroup}
        onItemPress={onItemPress}
      />
    );

    fireEvent.press(screen.getByText('Milk'));

    expect(onItemPress).toHaveBeenCalledWith('Milk');
  });
});

describe('groupByArea excludes one-offs from area groups', () => {
  const { groupByArea } = require('../../src/domain/item-grouping');
  const { getOneOffItems } = require('../../src/domain/item-grouping');

  const ALL_AREAS = ['Fridge', 'Bathroom', 'Kitchen Cabinets'] as const;

  const makeItem = (overrides: Partial<TripItem>): TripItem => ({
    id: 'item-1',
    name: 'Milk',
    houseArea: 'Fridge',
    storeLocation: { section: 'Dairy', aisleNumber: 2 },
    itemType: 'staple',
    stapleId: 'staple-1',
    source: 'preloaded',
    needed: true,
    checked: false,
    checkedAt: null,
    ...overrides,
  });

  it('area groups contain only staple items when mix of staples and one-offs provided', () => {
    const staple = makeItem({ id: 's1', name: 'Milk', itemType: 'staple', houseArea: 'Fridge' });
    const oneOff = makeItem({ id: 'o1', name: 'Birthday Candles', itemType: 'one-off', houseArea: 'Fridge' });

    const result = groupByArea([staple, oneOff], ALL_AREAS);

    const fridgeGroup = result.find((g: { area: string }) => g.area === 'Fridge')!;
    expect(fridgeGroup.items).toHaveLength(1);
    expect(fridgeGroup.items[0].name).toBe('Milk');
  });

  it('one-off items are excluded from all area groups', () => {
    const oneOff = makeItem({ id: 'o1', name: 'Party Cups', itemType: 'one-off', houseArea: 'Bathroom' });

    const result = groupByArea([oneOff], ALL_AREAS);

    const allItems = result.flatMap((g: { items: TripItem[] }) => g.items);
    expect(allItems).toHaveLength(0);
  });

  it('getOneOffItems returns only one-off items', () => {
    const staple = makeItem({ id: 's1', name: 'Milk', itemType: 'staple' });
    const oneOff1 = makeItem({ id: 'o1', name: 'Birthday Candles', itemType: 'one-off' });
    const oneOff2 = makeItem({ id: 'o2', name: 'Party Cups', itemType: 'one-off' });

    const result = getOneOffItems([staple, oneOff1, oneOff2]);

    expect(result).toHaveLength(2);
    expect(result.map((i: TripItem) => i.name)).toEqual(['Birthday Candles', 'Party Cups']);
  });
});

describe('sweep mode shows one-offs section separately', () => {
  function renderAppWithOneOff() {
    const stapleStorage = createNullStapleStorage([
      { name: 'Milk', houseArea: 'Fridge', storeLocation: { section: 'Dairy', aisleNumber: 3 } },
    ]);
    const stapleLibrary = createStapleLibrary(stapleStorage);
    const tripStorage = createNullTripStorage();
    const tripService = createTrip(tripStorage);
    tripService.start(stapleLibrary.listAll());

    tripService.addItem({
      name: 'Birthday Candles',
      houseArea: 'Kitchen Cabinets',
      storeLocation: { section: 'Baking', aisleNumber: 12 },
      itemType: 'one-off',
      source: 'quick-add',
    });

    render(
      <ServiceProvider stapleLibrary={stapleLibrary} tripService={tripService}>
        <AppShell />
      </ServiceProvider>
    );

    return { tripService };
  }

  it('renders One-offs section with one-off items in sweep mode', () => {
    renderAppWithOneOff();

    expect(screen.getByText('One-offs (1)')).toBeTruthy();
    expect(screen.getByText('Birthday Candles')).toBeTruthy();
  });

  it('does not render One-offs section when no one-off items exist', () => {
    const stapleStorage = createNullStapleStorage([
      { name: 'Milk', houseArea: 'Fridge', storeLocation: { section: 'Dairy', aisleNumber: 3 } },
    ]);
    const stapleLibrary = createStapleLibrary(stapleStorage);
    const tripStorage = createNullTripStorage();
    const tripService = createTrip(tripStorage);
    tripService.start(stapleLibrary.listAll());

    render(
      <ServiceProvider stapleLibrary={stapleLibrary} tripService={tripService}>
        <AppShell />
      </ServiceProvider>
    );

    expect(screen.queryByText(/One-offs/)).toBeNull();
  });

  it('one-off item tap toggles needed state', () => {
    renderAppWithOneOff();

    const item = screen.getByText('Birthday Candles');
    fireEvent.press(item);

    // After tap, item should be skipped (grey strikethrough)
    const flatStyle = Array.isArray(item.props.style)
      ? Object.assign({}, ...item.props.style.filter(Boolean))
      : item.props.style;

    expect(flatStyle.color).toBe('#6B6B6B');
  });
});

