/**
 * Regression test for Area Settings screen.
 *
 * Verifies that a settings gear on HomeView opens an AreaSettingsScreen
 * showing configured house areas with an "Add Area" button.
 */

import React from 'react';
import { render, fireEvent, screen, waitFor } from '@testing-library/react-native';
import { ServiceProvider } from '../../../src/ui/ServiceProvider';
import { AppShell } from '../../../src/ui/AppShell';
import { createStapleLibrary } from '../../../src/domain/staple-library';
import { createNullStapleStorage } from '../../../src/adapters/null/null-staple-storage';
import { createNullTripStorage } from '../../../src/adapters/null/null-trip-storage';
import { createNullAreaStorage } from '../../../src/adapters/null/null-area-storage';
import { createTrip } from '../../../src/domain/trip';
import { createAreaManagement } from '../../../src/domain/area-management';
import { StapleItem } from '../../../src/domain/types';

function makeStaple(name: string, houseArea: string): StapleItem {
  return {
    id: `${name}-${houseArea}`,
    name,
    houseArea,
    storeLocation: { section: 'A', aisleNumber: 1 },
    type: 'staple',
    createdAt: new Date().toISOString(),
  };
}

function createTestServices(
  areas: string[] = ['Bathroom', 'Kitchen', 'Garage'],
  staples: StapleItem[] = [],
) {
  const stapleStorage = createNullStapleStorage(staples);
  const tripStorage = createNullTripStorage();
  const areaStorage = createNullAreaStorage(areas);
  const stapleLibrary = createStapleLibrary(stapleStorage);
  const tripService = createTrip(tripStorage);
  const areaManagement = createAreaManagement(areaStorage, stapleStorage, tripStorage);
  tripService.start(stapleLibrary.listAll());
  return { stapleLibrary, tripService, areaManagement };
}

function renderApp(areas?: string[], staples: StapleItem[] = []) {
  const { stapleLibrary, tripService, areaManagement } = createTestServices(areas, staples);
  return render(
    <ServiceProvider stapleLibrary={stapleLibrary} tripService={tripService} areaManagement={areaManagement}>
      <AppShell />
    </ServiceProvider>
  );
}

describe('Area Settings Screen', () => {
  it('settings gear on HomeView opens AreaSettingsScreen showing configured areas', () => {
    renderApp(['Bathroom', 'Kitchen', 'Garage']);

    // Tap the settings gear
    fireEvent.press(screen.getByTestId('settings-button'));

    // Verify area settings screen is visible with all configured areas
    expect(screen.getByText('House Areas')).toBeTruthy();
    expect(screen.getByText('Bathroom')).toBeTruthy();
    expect(screen.getByText('Kitchen')).toBeTruthy();
    expect(screen.getByText('Garage')).toBeTruthy();
  });

  it('AreaSettingsScreen shows an Add Area button', () => {
    renderApp();

    fireEvent.press(screen.getByTestId('settings-button'));

    expect(screen.getByText('Add Area')).toBeTruthy();
  });

  describe('Add Area', () => {
    it('tapping Add Area opens name input, typing and saving adds area to list', () => {
      renderApp(['Bathroom', 'Kitchen']);

      fireEvent.press(screen.getByTestId('settings-button'));
      fireEvent.press(screen.getByText('Add Area'));

      // Input and Save/Cancel buttons should be visible
      const nameInput = screen.getByTestId('area-name-input');
      expect(nameInput).toBeTruthy();
      expect(screen.getByText('Save')).toBeTruthy();
      expect(screen.getByText('Cancel')).toBeTruthy();

      // Type a new area name and save
      fireEvent.changeText(nameInput, 'Garage');
      fireEvent.press(screen.getByText('Save'));

      // New area should appear in the list
      expect(screen.getByText('Garage')).toBeTruthy();
      // Input should be hidden after saving
      expect(screen.queryByTestId('area-name-input')).toBeNull();
    });

    it('blocks empty area name with error message', () => {
      renderApp(['Bathroom', 'Kitchen']);

      fireEvent.press(screen.getByTestId('settings-button'));
      fireEvent.press(screen.getByText('Add Area'));

      // Try to save with empty name
      fireEvent.press(screen.getByText('Save'));

      // Error message should appear
      expect(screen.getByText('Area name is required')).toBeTruthy();
      // Input should still be visible
      expect(screen.getByTestId('area-name-input')).toBeTruthy();
    });

    it('blocks duplicate area name with error message', () => {
      renderApp(['Bathroom', 'Kitchen']);

      fireEvent.press(screen.getByTestId('settings-button'));
      fireEvent.press(screen.getByText('Add Area'));

      fireEvent.changeText(screen.getByTestId('area-name-input'), 'Bathroom');
      fireEvent.press(screen.getByText('Save'));

      // Error message should appear
      expect(screen.getByText('"Bathroom" already exists')).toBeTruthy();
    });

    it('Cancel hides the input without adding', () => {
      renderApp(['Bathroom', 'Kitchen']);

      fireEvent.press(screen.getByTestId('settings-button'));
      fireEvent.press(screen.getByText('Add Area'));

      fireEvent.changeText(screen.getByTestId('area-name-input'), 'Garage');
      fireEvent.press(screen.getByText('Cancel'));

      // Input should be hidden
      expect(screen.queryByTestId('area-name-input')).toBeNull();
      // Garage should NOT have been added
      expect(screen.queryByText('Garage')).toBeNull();
    });
  });

  describe('Rename Area', () => {
    it('tapping Edit on an area row opens rename input with current name pre-filled', () => {
      renderApp(['Bathroom', 'Kitchen']);

      fireEvent.press(screen.getByTestId('settings-button'));

      // Tap Edit on the Bathroom row
      fireEvent.press(screen.getByTestId('edit-area-Bathroom'));

      // Input should have current name pre-filled
      const renameInput = screen.getByTestId('rename-area-input');
      expect(renameInput.props.value).toBe('Bathroom');
    });

    it('saving a renamed area updates the list', () => {
      renderApp(['Bathroom', 'Kitchen']);

      fireEvent.press(screen.getByTestId('settings-button'));
      fireEvent.press(screen.getByTestId('edit-area-Bathroom'));

      const renameInput = screen.getByTestId('rename-area-input');
      fireEvent.changeText(renameInput, 'Master Bath');
      fireEvent.press(screen.getByText('Save'));

      // Old name gone, new name present
      expect(screen.queryByText('Bathroom')).toBeNull();
      expect(screen.getByText('Master Bath')).toBeTruthy();
      // Input should be hidden
      expect(screen.queryByTestId('rename-area-input')).toBeNull();
    });

    it('shows error when renaming to an existing area name', () => {
      renderApp(['Bathroom', 'Kitchen']);

      fireEvent.press(screen.getByTestId('settings-button'));
      fireEvent.press(screen.getByTestId('edit-area-Bathroom'));

      fireEvent.changeText(screen.getByTestId('rename-area-input'), 'Kitchen');
      fireEvent.press(screen.getByText('Save'));

      expect(screen.getByText('"Kitchen" already exists')).toBeTruthy();
      // Input should remain visible
      expect(screen.getByTestId('rename-area-input')).toBeTruthy();
    });
  });

  describe('Delete Area', () => {
    it('deleting empty area shows confirmation and removes on confirm', () => {
      renderApp(['Bathroom', 'Kitchen', 'Garage']);

      fireEvent.press(screen.getByTestId('settings-button'));
      fireEvent.press(screen.getByTestId('delete-area-Kitchen'));

      // Confirmation dialog visible
      expect(screen.getByText('Delete Kitchen?')).toBeTruthy();
      fireEvent.press(screen.getByTestId('confirm-delete-button'));

      // Kitchen should be gone
      expect(screen.queryByText('Kitchen')).toBeNull();
      // Others remain
      expect(screen.getByText('Bathroom')).toBeTruthy();
      expect(screen.getByText('Garage')).toBeTruthy();
    });

    it('blocks deleting the last remaining area', () => {
      renderApp(['Kitchen']);

      fireEvent.press(screen.getByTestId('settings-button'));
      fireEvent.press(screen.getByTestId('delete-area-Kitchen'));

      expect(screen.getByText('Cannot delete: at least one area must remain')).toBeTruthy();
    });

    it('area with staples shows reassignment picker and deletes on confirm', () => {
      const staples = [makeStaple('Soap', 'Bathroom'), makeStaple('Shampoo', 'Bathroom')];
      renderApp(['Bathroom', 'Kitchen', 'Garage'], staples);

      fireEvent.press(screen.getByTestId('settings-button'));
      fireEvent.press(screen.getByTestId('delete-area-Bathroom'));

      // Should show staple count and reassignment options
      expect(screen.getByText('2 staples in Bathroom. Move to:')).toBeTruthy();

      // Pick Kitchen as target
      fireEvent.press(screen.getByTestId('reassign-to-Kitchen'));
      fireEvent.press(screen.getByTestId('confirm-delete-and-move-button'));

      // Bathroom should be gone
      expect(screen.queryByText('2 staples in Bathroom. Move to:')).toBeNull();
      // Verify Bathroom is removed from the area list
      const areaNames = screen.getAllByTestId(/^delete-area-/);
      const areaTestIds = areaNames.map(el => el.props.testID);
      expect(areaTestIds).not.toContain('delete-area-Bathroom');
    });
  });
});

tests/regression/whiteboard-checklist.te.source:
/**
 * Regression test for StapleChecklist component (whiteboard phase).
 *
 * StapleChecklist renders an alphabetically sorted list of all staples.
 * Each staple shows its name and a toggle button.
 * Staples already on the trip show as checked.
 * Tapping unchecked staple calls onAddStaple; tapping checked calls onRemoveStaple.
 *
 * Integration: when all areas are complete in HomeView, StapleChecklist appears
 * below the whiteboard prompt. Adding/removing staples updates the trip.
 */

import React from 'react';
import { render, fireEvent, screen } from '@testing-library/react-native';
import { StapleChecklist } from '../../src/ui/StapleChecklist';
import { ServiceProvider } from '../../src/ui/ServiceProvider';
import { AppShell } from '../../src/ui/AppShell';
import { createStapleLibrary } from '../../src/domain/staple-library';
import { createNullStapleStorage } from '../../src/adapters/null/null-staple-storage';
import { createNullTripStorage } from '../../src/adapters/null/null-trip-storage';
import { createNullAreaStorage } from '../../src/adapters/null/null-area-storage';
import { createTrip } from '../../src/domain/trip';
import { createAreaManagement } from '../../src/domain/area-management';
import { StapleItem } from '../../src/domain/types';

const createStaple = (name: string, houseArea: string): StapleItem => ({
  id: `id-${name.toLowerCase()}`,
  name,
  houseArea,
  storeLocation: { section: 'General', aisleNumber: null },
  type: 'staple',
  createdAt: '2026-01-01T00:00:00Z',
});

const STAPLES: readonly StapleItem[] = [
  createStaple('Milk', 'Fridge'),
  createStaple('Apples', 'Pantry'),
  createStaple('Bread', 'Pantry'),
  createStaple('Cheese', 'Fridge'),
];

describe('staple checklist renders sorted list with toggle', () => {
  it('renders staples in alphabetical order by name', () => {
    const onAddStaple = jest.fn();
    const onRemoveStaple = jest.fn();

    render(
      <StapleChecklist
        staples={STAPLES}
        tripItemNames={new Set<string>()}
        onAddStaple={onAddStaple}
        onRemoveStaple={onRemoveStaple}
      />
    );

    const stapleNames = screen.getAllByTestId(/^staple-row-/).map(
      (element) => element.props.testID
    );

    expect(stapleNames).toEqual([
      'staple-row-Apples',
      'staple-row-Bread',
      'staple-row-Cheese',
      'staple-row-Milk',
    ]);
  });

  it('shows each staple name and area label', () => {
    render(
      <StapleChecklist
        staples={STAPLES}
        tripItemNames={new Set<string>()}
        onAddStaple={jest.fn()}
        onRemoveStaple={jest.fn()}
      />
    );

    expect(screen.getByText('Apples')).toBeTruthy();
    expect(screen.getAllByText('Fridge').length).toBeGreaterThanOrEqual(1);
    expect(screen.getAllByText('Pantry').length).toBeGreaterThanOrEqual(1);
  });

  it('marks staples on the trip with green text; staples not on trip with strikethrough', () => {
    const tripItemNames = new Set(['Milk', 'Bread']);

    render(
      <StapleChecklist
        staples={STAPLES}
        tripItemNames={tripItemNames}
        onAddStaple={jest.fn()}
        onRemoveStaple={jest.fn()}
      />
    );

    // Checked staples: green text, no strikethrough
    expect(screen.getByText('Milk')).toHaveStyle({ color: '#1A1A1A' });
    expect(screen.getByText('Bread')).toHaveStyle({ color: '#1A1A1A' });
    // Unchecked staples: gray strikethrough
    expect(screen.getByText('Apples')).toHaveStyle({ color: '#6B6B6B', textDecorationLine: 'line-through' });
    expect(screen.getByText('Cheese')).toHaveStyle({ color: '#6B6B6B', textDecorationLine: 'line-through' });
  });

  it('calls onAddStaple when tapping an unchecked staple', () => {
    const onAddStaple = jest.fn();
    const tripItemNames = new Set(['Milk']);

    render(
      <StapleChecklist
        staples={STAPLES}
        tripItemNames={tripItemNames}
        onAddStaple={onAddStaple}
        onRemoveStaple={jest.fn()}
      />
    );

    fireEvent.press(screen.getByTestId('staple-row-Apples'));

    expect(onAddStaple).toHaveBeenCalledTimes(1);
    expect(onAddStaple).toHaveBeenCalledWith(
      expect.objectContaining({ name: 'Apples', houseArea: 'Pantry' })
    );
  });

  it('calls onRemoveStaple when tapping a checked staple', () => {
    const onRemoveStaple = jest.fn();
    const tripItemNames = new Set(['Milk']);

    render(
      <StapleChecklist
        staples={STAPLES}
        tripItemNames={tripItemNames}
        onAddStaple={jest.fn()}
        onRemoveStaple={onRemoveStaple}
      />
    );

    fireEvent.press(screen.getByTestId('staple-row-Milk'));

    expect(onRemoveStaple).toHaveBeenCalledTimes(1);
    expect(onRemoveStaple).toHaveBeenCalledWith('Milk');
  });
});

function renderAppInChecklistMode() {
  const stapleStorage = createNullStapleStorage([
    { name: 'Milk', houseArea: 'Fridge', storeLocation: { section: 'Dairy', aisleNumber: 3 } },
    { name: 'Bread', houseArea: 'Pantry', storeLocation: { section: 'Bakery', aisleNumber: null } },
  ]);
  const stapleLibrary = createStapleLibrary(stapleStorage);
  const tripStorage = createNullTripStorage();
  const tripAreas = ['Fridge', 'Pantry'];
  const tripService = createTrip(tripStorage, tripAreas);
  tripService.start(stapleLibrary.listAll());

  const areaStorage = createNullAreaStorage(tripAreas);
  const areaManagement = createAreaManagement(areaStorage, stapleStorage, tripStorage);

  render(
    <ServiceProvider stapleLibrary={stapleLibrary} tripService={tripService} areaManagement={areaManagement}>
      <AppShell />
    </ServiceProvider>
  );

  // Switch to checklist mode to see the StapleChecklist
  fireEvent.press(screen.getByTestId('home-mode-checklist'));
}

describe('preloaded staples show as already on trip', () => {
  it('preloaded staples that are needed show green; skipped staples show strikethrough', () => {
    const stapleStorage = createNullStapleStorage([
      { name: 'Milk', houseArea: 'Fridge', storeLocation: { section: 'Dairy', aisleNumber: 3 } },
      { name: 'Bread', houseArea: 'Pantry', storeLocation: { section: 'Bakery', aisleNumber: null } },
      { name: 'Eggs', houseArea: 'Fridge', storeLocation: { section: 'Dairy', aisleNumber: 3 } },
    ]);
    const stapleLibrary = createStapleLibrary(stapleStorage);
    const tripStorage = createNullTripStorage();
    const tripAreas = ['Fridge', 'Pantry'];
    const tripService = createTrip(tripStorage, tripAreas);
    tripService.start(stapleLibrary.listAll());

    // Skip Eggs during the sweep phase (needed becomes false)
    tripService.skipItem('Eggs');

    const areaStorage = createNullAreaStorage(tripAreas);
    const areaManagement = createAreaManagement(areaStorage, stapleStorage, tripStorage);

    render(
      <ServiceProvider stapleLibrary={stapleLibrary} tripService={tripService} areaManagement={areaManagement}>
        <AppShell />
      </ServiceProvider>
    );

    // Switch to checklist mode to see StapleChecklist
    fireEvent.press(screen.getByTestId('home-mode-checklist'));

    // Preloaded and still needed -> green text
    expect(screen.getByText('Milk')).toHaveStyle({ color: '#1A1A1A' });
    expect(screen.getByText('Bread')).toHaveStyle({ color: '#1A1A1A' });

    // Preloaded but skipped (needed=false) -> strikethrough
    expect(screen.getByText('Eggs')).toHaveStyle({ color: '#6B6B6B', textDecorationLine: 'line-through' });
  });
});

describe('checklist mode shows staple checklist', () => {
  it('renders StapleChecklist in checklist mode', () => {
    renderAppInChecklistMode();

    // Staple checklist rows should appear
    expect(screen.getByTestId('staple-row-Bread')).toBeTruthy();
    expect(screen.getByTestId('staple-row-Milk')).toBeTruthy();
  });

  it('preloaded staples show as green in checklist mode', () => {
    renderAppInChecklistMode();

    // Both staples are already on the trip from preload, so they should be green
    expect(screen.getByText('Milk')).toHaveStyle({ color: '#1A1A1A' });
    expect(screen.getByText('Bread')).toHaveStyle({ color: '#1A1A1A' });
  });

  it('tapping a checked staple skips it and shows strikethrough', () => {
    renderAppInChecklistMode();

    // Tap Milk (already on trip = green) to skip it
    fireEvent.press(screen.getByTestId('staple-row-Milk'));

    // After skip, Milk should show strikethrough
    expect(screen.getByText('Milk')).toHaveStyle({ color: '#6B6B6B', textDecorationLine: 'line-through' });
  });

  it('tapping a skipped staple unskips it and shows green', () => {
    renderAppInChecklistMode();

    // First skip Milk
    fireEvent.press(screen.getByTestId('staple-row-Milk'));
    expect(screen.getByText('Milk')).toHaveStyle({ textDecorationLine: 'line-through' });

    // Now tap Milk again to unskip it
    fireEvent.press(screen.getByTestId('staple-row-Milk'));
    expect(screen.getByText('Milk')).toHaveStyle({ color: '#1A1A1A' });
  });
});

